module mac_address_filter (
    input  [47:0] mac_address,
    input  [47:0] filter_address,
    output match
);
      wire _n01 = mac_address[0] ^ filter_address[0];
  wire _n02 = mac_address[1] ^ filter_address[1];
  wire _n03 = mac_address[2] ^ filter_address[2];
  wire _n04 = mac_address[3] ^ filter_address[3];
  assign match = ~_n01 & ~_n02 & ~_n03 & ~_n04;
endmodule
